  ('customs-f19eb2bd-moex-00487', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '若某船以航速20節，依航向205°行駛，於0800時，觀測目標A方位為180°，又於0818時再觀測目標 A，得方位為155°；則在0818時，該船與目標A的距離為何？', '["6浬", "8浬", "10.5浬", "11.5浬"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00488', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '美國國家海洋及大氣總署（NOAA）刊行之潮流表（TidalCurrentTable）之第一表，有關基準站（Reference Station）資料之敘述，下列何者錯誤？', '["記述每日憩流之時間", "記述每日漲潮流或落潮流最大流速之時間及速度", "記述E表示漲潮流，F表示落潮流", "記述典型潮流曲線（TypicalCurrentCurves）之落潮流以虛線表示於憩流之下方"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00489', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '採用截距法（IM）繪製天文位置線（LOP）之程序中，下列敘述何者錯誤？', '["計算高度（Hc）與觀測高度（Ho）之差稱為高度截距，簡稱截距（a）", "當Hc大於Ho時，觀測者之實際位置較假定船位遠離天體之GP", "當Ho大於Hc時，觀測者之實際位置較假定船位接近天體之GP", "截距（a）通常由GP繪出，其後標註T表示離GP之方向"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00490', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '某天文台其經度為77°04.0''W，某船經度位於19°56.0''E。若當天文台之時間為12-00-00 LMT時，則該船 的時間為下列何者？', '["05-32-00LMT", "12-06-28LMT", "18-28-00LMT", "19-25-20LMT"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00491', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '某船位於經度118°15.0''W，若航海員在航海曆中得知4月23日之日出時間為LMT 0550，則該日出時間 的ZT為下列何者？', '["ZT為0543；4月23日", "ZT為0557；4月23日", "ZT為0603；4月24日", "ZT為0608；4月24日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00492', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '「將外力施於高速旋轉中之迴轉儀軸上，該軸並不依照所施外力之方向旋轉，而與外力成 90°之方向轉 動」，此段敘述在電羅經學中，稱之為何？', '["旋轉惰性", "旋轉慣性", "旋轉偏移", "旋轉反制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00493', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '某船以真航向 220°航行，由於電羅經故障改以磁羅經航駛。若海圖上之羅經花（Compass rose）內標示 Var.3°30''W（2002）AnnualDecreases1.5''，且得知本船之自差為3°E，則該船應航駛磁航向為下列何者？', '["217°", "220°", "223°", "226°"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00494', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '自動測繪雷達（AutomaticRadarPlottingAid,ARPA）可提供目標物的基本資訊等敘述，下列何者正確？', '["目標的高度（Height）", "目標船的船旗國（Nationality）", "目標與本船最近的距離（CPA）與到達之時間（TCPA）", "目標船的貨載（Cargo）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00495', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '影響GPS（GlobalPositioningSystem）定位誤差的因素中，下列何者所造成之誤差值為最大？', '["電離層延遲誤差", "對流層延遲誤差", "時鐘差", "多路徑誤差"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00496', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '「利用一已知位置之基地站，接收所有在其水平線上的GPS衛星信號，再由該已知基地站位置計算各衛 星之距離修正值，發送給有效範圍內的GPS用戶接收並修正後使用」，此敘述係為下列何者？', '["幾何釋度（GeometricDilutionofPrecision;GDOP）", "差分全球定位系統（DifferentialGPS;DGPS）", "平面幾何釋度（Horizontal-DOP;HDOP）", "位置幾何釋度（Position-DOP;PDOP）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
